using System.ClientModel;
using System.ComponentModel;
using System.Text.Json;
using Microsoft.Extensions.AI;
using OpenAI;

// ---------------------------------------------------------------------------
// Configuration
// ---------------------------------------------------------------------------
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

// ---------------------------------------------------------------------------
// Tools
// ---------------------------------------------------------------------------
var notebook = new Notebook();

IChatClient client = new ChatClientBuilder(
        new OpenAIClient(new ApiKeyCredential(apiKey))
            .GetChatClient(model).AsIChatClient())
    .UseFunctionInvocation()
    .Build();

var chatOptions = new ChatOptions
{
    Tools =
    [
        AIFunctionFactory.Create(SearchWeb),
        AIFunctionFactory.Create(notebook.SaveNote),
        AIFunctionFactory.Create(notebook.GetNotes),
    ],
};

// ---------------------------------------------------------------------------
// Agent loop
// ---------------------------------------------------------------------------
Console.WriteLine("=== Research Agent ===");
Console.WriteLine("Enter a topic to research (or 'quit' to exit):\n");

while (true)
{
    Console.ForegroundColor = ConsoleColor.Cyan;
    Console.Write("> ");
    Console.ResetColor();

    var topic = Console.ReadLine()?.Trim();
    if (string.IsNullOrEmpty(topic) || topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
        break;

    notebook.Clear();

    var messages = new List<ChatMessage>
    {
        new(ChatRole.System, """
            You are a research agent. When the user gives you a topic:
            1. Search the web multiple times with varied queries to gather information.
            2. Save important findings as notes using the save_note tool.
            3. After gathering enough information, retrieve your notes and produce a
               well-structured summary with key facts, different perspectives, and sources.
            Be thorough — perform at least 2-3 searches before summarising.
            """),
        new(ChatRole.User, $"Research this topic: {topic}"),
    };

    Console.ForegroundColor = ConsoleColor.DarkGray;
    Console.WriteLine("\nResearching…\n");
    Console.ResetColor();

    var response = await client.GetResponseAsync(messages, chatOptions);

    Console.ForegroundColor = ConsoleColor.Green;
    Console.WriteLine(response.Text);
    Console.ResetColor();
    Console.WriteLine();
}

Console.WriteLine("Goodbye!");
return;

// ---------------------------------------------------------------------------
// Web search tool — uses Wikipedia's public API (no key required)
// ---------------------------------------------------------------------------
[Description("Search the web for information. Returns relevant snippets for the query.")]
static async Task<string> SearchWeb(
    [Description("The search query")] string query)
{
    using var http = new HttpClient();
    http.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");

    var url =
        $"https://en.wikipedia.org/w/api.php?action=query&list=search"
        + $"&srsearch={Uri.EscapeDataString(query)}&format=json&srlimit=5&srprop=snippet|titlesnippet";

    try
    {
        var json = await http.GetStringAsync(url);

        using var doc = JsonDocument.Parse(json);
        var results = doc.RootElement
            .GetProperty("query")
            .GetProperty("search")
            .EnumerateArray()
            .Select(r => $"• {r.GetProperty("title").GetString()}: "
                       + $"{StripHtml(r.GetProperty("snippet").GetString() ?? "")}")
            .ToList();

        return results.Count > 0
            ? string.Join("\n", results)
            : "No results found.";
    }
    catch (Exception ex)
    {
        return $"Search failed: {ex.Message}";
    }
}

static string StripHtml(string html) =>
    System.Text.RegularExpressions.Regex.Replace(html, "<.*?>", "");

// ---------------------------------------------------------------------------
// Notebook — simple in-memory note-taking tool
// ---------------------------------------------------------------------------
sealed class Notebook
{
    private readonly List<string> _notes = [];

    [Description("Save a research note. Use this to record important findings.")]
    public string SaveNote(
        [Description("The note text to save")] string note)
    {
        _notes.Add(note);
        return $"Note #{_notes.Count} saved.";
    }

    [Description("Retrieve all saved research notes.")]
    public string GetNotes()
    {
        return _notes.Count == 0
            ? "No notes saved yet."
            : string.Join("\n\n", _notes.Select((n, i) => $"[Note {i + 1}] {n}"));
    }

    public void Clear() => _notes.Clear();
}

